  (gen_random_uuid(), 'room-subject-teaching--community--english-foreign-language', 'room-subject-teaching--community--english-foreign-language-t1', 'タイガ', '高3生', '間違いを気にせず話せる相手ができるのは大きいです。', false, now() - interval '2257 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--moral-education', 'room-subject-teaching--community--moral-education-t1', 'しんじ', '道徳研究会', '多様な立場の意見をAIに出させ、議論の材料にするのは面白い試みです。', false, now() - interval '2294 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--pe-health', 'room-subject-teaching--community--pe-health-t1', 'まっちょ', '体育会系', '動作をAIで撮って分析すると、苦手な子も上達を実感できます。', false, now() - interval '2331 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--music-art', 'room-subject-teaching--community--music-art-t1', 'ドレミ', '音楽', 'AIで作曲や画像生成を体験させると、表現の入り口が広がります。', false, now() - interval '2368 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--home-economics-technology', 'room-subject-teaching--community--home-economics-technology-t1', 'おむすび', '家庭科', '献立の栄養計算や被服の型紙づくりなど、AIで効率化できる作業は多いです。', false, now() - interval '2405 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--integrated-inquiry-time', 'room-subject-teaching--community--integrated-inquiry-time-t1', 'はるか', '探究コーディネーター', '調べてまとめるだけならAIが代行できる時代。だからこそ総合では『どんな問いを立てるか』『得た答えをどう吟味するか』に重心を移し、AIは情報収集の相棒として位置づけたいです。', false, now() - interval '2442 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--integrated-inquiry-time', 'room-subject-teaching--community--integrated-inquiry-time-t1', 'ごましお', '主幹教諭', '教科横断のテーマ設定にAIの助けは大きい。', false, now() - interval '2479 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--information-subject', 'room-subject-teaching--community--information-subject-t1', 'テック岡', '情報科', 'プログラミングの初学者がAIに質問しながら学べるのは大きな利点です。', false, now() - interval '2516 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--information-subject', 'room-subject-teaching--community--information-subject-t1', '父さん', '元エンジニア', 'ただAIにコードを丸ごと書かせると、なぜ動くかを理解しないまま進んでしまう。生成物を読み解き、直し、説明できる力をセットで育てないと『使えるが分からない』状態に陥ると思います。', false, now() - interval '2553 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--information-subject', 'room-subject-teaching--community--information-subject-t1', 'ふじやま', '校務DX担当', '情報モラルも実例で学べる教材になります。', false, now() - interval '2590 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--career-guidance', 'room-subject-teaching--community--career-guidance-t1', 'はるか', '探究コーディネーター', '適性や選択肢をAIで可視化するのは有効だが、最後に『どう生きたいか』を考えるのは本人。データが示す『向いている』に流されず、本人の主体性を育てる支援とセットで使いたいです。', false, now() - interval '2627 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--career-guidance', 'room-subject-teaching--community--career-guidance-t1', 'うめ子', '高校国語', '偏差値だけでない進路の見せ方ができそうです。', false, now() - interval '2664 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--digital-textbook', 'room-ai-technology--community--digital-textbook-t2', 'うめ子', '高校国語', '長文をじっくり読む力は、紙のほうが育ちやすいと感じます。', false, now() - interval '2701 minutes'),
