  (gen_random_uuid(), 'room-ai-technology--community--digital-textbook', 'room-ai-technology--community--digital-textbook-t2', 'まろん', '養護教諭', '目への負担や姿勢の問題も、読解以前に気になるところです。', false, now() - interval '2775 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--edtech-adoption', 'room-ai-technology--community--edtech-adoption-t2', 'ふじやま', '校務DX担当', 'もはや民間サービスなしに学校は回らない。問題は依存の『質』だと思います。', false, now() - interval '2812 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--edtech-adoption', 'room-ai-technology--community--edtech-adoption-t2', 'テック岡', '情報科', '特定の企業に深く依存すると、値上げやサービス終了のたびに現場が振り回される。データの持ち出しやすさ、乗り換えのしやすさを契約時に確認しておくことが、長期的なリスク管理になると思います。', false, now() - interval '2849 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--ai-literacy-moral', 'room-ai-technology--community--ai-literacy-moral-t2', 'れきお', '社会科', '『一次情報にあたる』習慣を低学年から。', false, now() - interval '2886 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--ai-literacy-moral', 'room-ai-technology--community--ai-literacy-moral-t2', 'テック岡', '情報科', '誤情報や生成AIによる偽画像が湢れる今、見抜く力は必須スキル。ただ『疑え』と教えるだけでは萎縮する。複数の情報源を照らし合わせ、確からしさを自分で確かめる手順を、具体例で繰り返し練習させたいです。', false, now() - interval '2923 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--ai-literacy-moral', 'room-ai-technology--community--ai-literacy-moral-t2', 'とんかつ', '保護者会長', '家庭でもSNSの情報を鵜呑みにしがち。学校で学んだことを家でも話せるといいです。', false, now() - interval '2960 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--ai-literacy-moral', 'room-ai-technology--community--ai-literacy-moral-t2', 'コタロー', '大学院生', '『無料』の裏側を考える教材にもなります。', false, now() - interval '2997 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--personalized-learning', 'room-ai-technology--community--personalized-learning-t2', 'カエル先生', '中学数学', '基礎の反復はアダプティブ教材に任せ、浮いた時間を話し合いに回すのが現実的です。', false, now() - interval '3034 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--personalized-learning', 'room-ai-technology--community--personalized-learning-t2', 'はるか', '探究コーディネーター', '個別最適と一斉授業は対立しない。一人で進める時間と、みんなで考えを交わす時間を意図的に組み合わせることで、効率と深まりの両方が得られる。教員の授業デザイン力が問われるところだと思います。', false, now() - interval '3071 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--inquiry-pbl', 'room-evaluation-curriculum--community--inquiry-pbl-t2', 'はるか', '探究コーディネーター', '成果物の完成度で測ると、見栄えのよい発表が評価されがち。本当に見たいのは『調べる途中で考えが変わった瞬間』を語れるか。思考の跡を評価する視点への転換が必要だと思います。', false, now() - interval '3108 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--inquiry-pbl', 'room-evaluation-curriculum--community--inquiry-pbl-t2', 'ごましお', '主幹教諭', 'ルーブリックを生徒と共有すると公正になります。', false, now() - interval '3145 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--homework', 'room-evaluation-curriculum--community--homework-t2', 'カエル先生', '中学数学', '丸つけは自動採点に任せ、教員は見取りに集中したい。', false, now() - interval '3182 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--homework', 'room-evaluation-curriculum--community--homework-t2', 'ごましお', '主幹教諭', '提出状況の管理や丸つけに時間を取られ、肝心の『つまずきの分析』まで手が回らないのが現場の悩み。AIや相互採点を取り入れ、教員は一人ひとりの理解度を見る時間に振り向けるべきだと思います。', false, now() - interval '3219 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--homework', 'room-evaluation-curriculum--community--homework-t2', 'ぱんだ', '小学校教員', '宿題の提出状況から家庭の状況が見える面もあり、悩ましいところです。', false, now() - interval '3256 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--course-of-study-revision', 'room-evaluation-curriculum--community--course-of-study-revision-t2', 'タケじい', '元校長', '二項対立で語るより、何を核として残すかを先に決めるべきだと思います。', false, now() - interval '3293 minutes'),
