  (gen_random_uuid(), 'room-evaluation-curriculum--community--non-cognitive-skills', 'room-evaluation-curriculum--community--non-cognitive-skills-t2', 'コタロー', '大学院生', '数値で測ろうとした瞬間、本来の良さが歪む危うさがあります。', false, now() - interval '3404 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--non-cognitive-skills', 'room-evaluation-curriculum--community--non-cognitive-skills-t2', 'ごましお', '主幹教諭', '粘り強さや協働性は、テストのように点数化しにくい。だからといって評価しないと指導の手がかりも失う。観察記録やポートフォリオで『変化の過程』を見取る、緩やかな評価が現実解だと思います。', false, now() - interval '3441 minutes'),
