  (gen_random_uuid(), 'room-children-rights-discipline--community--school-rules-guidance', 'room-children-rights-discipline--community--school-rules-guidance-t2', 'ごましお', '主幹教諭', '下着の色指定や地毛証明など、合理的な説明ができない決まりは見直すべき。ただ現場には『ルールが多いほうが指導は楽』という本音もある。だからこそ目的を定期的に問い直す仕組みが要ると思います。', false, now() - interval '3515 minutes'),
