  (gen_random_uuid(), 'room-children-rights-discipline--community--school-rules-guidance', 'room-children-rights-discipline--community--school-rules-guidance-t2', 'ミント', '中2女子', '中学のとき、意味不明な校則が多かった。', false, now() - interval '3589 minutes'),
  (gen_random_uuid(), 'room-children-rights-discipline--community--bullying-prevention', 'room-children-rights-discipline--community--bullying-prevention-t2', '森のくま', 'スクールカウンセラー', '加害児童の背景には、本人の困りごとが隠れていることが多い。罰するだけでは繰り返す。ただし被害児童の安全確保が最優先で、両者を切り離したうえで加害側にも丁寧に関わる二段構えが要ると思います。', false, now() - interval '3626 minutes'),
  (gen_random_uuid(), 'room-children-rights-discipline--community--bullying-prevention', 'room-children-rights-discipline--community--bullying-prevention-t2', 'まろん', '養護教諭', 'まず被害児童が安心できる環境を。', false, now() - interval '3663 minutes'),
  (gen_random_uuid(), 'room-children-rights-discipline--community--bullying-prevention', 'room-children-rights-discipline--community--bullying-prevention-t2', 'ごましお', '主幹教諭', '担任一人で抱えず、組織と外部機関で対応する体制が不可欠です。', false, now() - interval '3700 minutes'),
  (gen_random_uuid(), 'room-children-rights-discipline--community--school-refusal-support', 'room-children-rights-discipline--community--school-refusal-support-t2', 'ルナ', '不登校経験者', '『復帰』をゴールにすると本人を追い詰めます。', false, now() - interval '3737 minutes'),
