  (gen_random_uuid(), 'room-children-rights-discipline--community--school-refusal-support', 'room-children-rights-discipline--community--school-refusal-support-t2', 'ゆずぽん', '3児の母', '親としては『戻ってほしい』と『無理させたくない』で揺れます。', false, now() - interval '3811 minutes'),
