  (gen_random_uuid(), 'room-children-rights-discipline--community--smartphone-sns', 'room-children-rights-discipline--community--smartphone-sns-t2', 'とんかつ', '保護者会長', '保護者としては学校だけに頼れません。', false, now() - interval '3922 minutes'),
  (gen_random_uuid(), 'room-children-rights-discipline--community--smartphone-sns', 'room-children-rights-discipline--community--smartphone-sns-t2', 'ミント', '中2女子', '匿名で相談できる窓口があると助かります。', false, now() - interval '3959 minutes'),
  (gen_random_uuid(), 'room-diversity-inclusion--community--inclusive-special-needs', 'room-diversity-inclusion--community--inclusive-special-needs-t2', 'クローバー', '特別支援', '分けるか混ぜるかの二択ではなく、その子にとって何が学びやすいかが基準。交流の機会を保ちつつ必要な支援は手厚くする柔軟な運用が理想だが、それを支える人員が足りないのが最大の壁です。', false, now() - interval '3996 minutes'),
  (gen_random_uuid(), 'room-diversity-inclusion--community--inclusive-special-needs', 'room-diversity-inclusion--community--inclusive-special-needs-t2', 'くるみ', '放デイ職員', '本人と保護者の希望を一番に。', false, now() - interval '4033 minutes'),
  (gen_random_uuid(), 'room-diversity-inclusion--community--inclusive-special-needs', 'room-diversity-inclusion--community--inclusive-special-needs-t2', 'ぱんだ', '小学校教員', '周りの子にとっても、多様な仲間と過ごす経験は財産になります。', false, now() - interval '4070 minutes'),
  (gen_random_uuid(), 'room-diversity-inclusion--community--multicultural-foreign-roots', 'room-diversity-inclusion--community--multicultural-foreign-roots-t2', 'セナ', '帰国子女', '母語の力は、実は日本語の習得を支える土台にもなります。', false, now() - interval '4107 minutes'),
  (gen_random_uuid(), 'room-diversity-inclusion--community--multicultural-foreign-roots', 'room-diversity-inclusion--community--multicultural-foreign-roots-t2', 'つばさ', 'NPO職員', '日本語指導を優先するあまり母語を切り捨てると、家族との会話やアイデンティティが揺らぐ。母語・母文化を保てる場を地域や保護者と協力して用意することが、結果的にその子の学びと安定につながると思います。', false, now() - interval '4144 minutes'),
  (gen_random_uuid(), 'room-teacher-school-system--community--teacher-work-style-reform', 'room-teacher-school-system--community--teacher-work-style-reform-t2', 'うめ子', '高校国語', '上限を図っても、持ち帰り仕事に変わるだけでは意味がありません。', false, now() - interval '4181 minutes'),
