  (gen_random_uuid(), 'room-teacher-school-system--community--teacher-work-style-reform', 'room-teacher-school-system--community--teacher-work-style-reform-t2', 'まっちょ', '体育会系', '部活の地域移行も鍵になります。', false, now() - interval '4255 minutes'),
  (gen_random_uuid(), 'room-teacher-school-system--community--school-consolidation', 'room-teacher-school-system--community--school-consolidation-t2', 'タケじい', '元校長', '学校は選挙の投票所、防災拠点、見守りの場として地域を支えてきた。統廃合で消えると、その機能ごと失われる。教育の効率だけでなく、地域インフラとしての役割も含めて判断すべきだと思います。', false, now() - interval '4292 minutes'),
  (gen_random_uuid(), 'room-teacher-school-system--community--school-consolidation', 'room-teacher-school-system--community--school-consolidation-t2', 'すずめ', '教育委員会', '残すなら維持コストの議論も避けられません。', false, now() - interval '4329 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--japanese-language', 'room-subject-teaching--community--japanese-language-t2', '父さん', '元エンジニア', '読めれば十分、書きは最小限でいいのでは。', false, now() - interval '4366 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--japanese-language', 'room-subject-teaching--community--japanese-language-t2', 'うめ子', '高校国語', '手で書く過程で字の構造を覚え、読みの力にもつながるという面がある。一方で社会では入力が主流。すべてを手書きで反復させるより、要点を絞って、デジタル入力の指導とバランスを取るのが現実的だと思います。', false, now() - interval '4403 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--japanese-language', 'room-subject-teaching--community--japanese-language-t2', 'ぱんだ', '小学校教員', '手書きには集中力や丁寧さを育てる側面もあると感じます。', false, now() - interval '4440 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--mathematics', 'room-subject-teaching--community--mathematics-t2', 'カエル先生', '中学数学', '計算手順の理解が先。そのうえで電卓を使うなら有効だと思います。', false, now() - interval '4477 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--mathematics', 'room-subject-teaching--community--mathematics-t2', 'カピバラ', '塾長', '電卓やアプリに頼ると計算力が落ちる、という懸念は根強い。でも社会では当たり前に使う道具。基礎の習得段階と、データ処理や応用の段階で、使わせ方を切り替える設計が要ると思います。', false, now() - interval '4514 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--science', 'room-subject-teaching--community--science-t2', 'モグラ', '中学理科', '知識の土台がなければ、探究は浅い調べ学習で終わる。逆に暗記だけでは使えない。基礎を効率よく固め、その知識を探究で活かす循環を作るのが、限られた時数の中での現実解だと思います。', false, now() - interval '4551 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--science', 'room-subject-teaching--community--science-t2', 'ごましお', '主幹教諭', '両方が要る、というのが現場の実感です。', false, now() - interval '4588 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--social-studies', 'room-subject-teaching--community--social-studies-t2', 'れきお', '社会科', '現代の論争的テーマを避けると、社会から切り離された学びになる。ただ扱う以上、教員の政治的中立性をどう保つかが要。結論を出すのではなく、複数の見方を提示し考えさせる訓練が教員側にも必要です。', false, now() - interval '4625 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--social-studies', 'room-subject-teaching--community--social-studies-t2', 'とんかつ', '保護者会長', '家庭の価値観との摩擦も生じやすい。', false, now() - interval '4662 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--social-studies', 'room-subject-teaching--community--social-studies-t2', 'しんじ', '道徳研究会', '答えのない問いを話し合う経験こそ、これからの社会で要る力です。', false, now() - interval '4699 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--english-foreign-language', 'room-subject-teaching--community--english-foreign-language-t2', 'ジョニー', '英語科', '文法・読解の土台がないと、会話も深まらないのが実感です。', false, now() - interval '4736 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--english-foreign-language', 'room-subject-teaching--community--english-foreign-language-t2', 'セナ', '帰国子女', '会話偏重で文法を軽視すると、込み入った内容を正確に伝えられなくなる。逆に文法ばかりでは話せない。翻訳AIがある今だからこそ、自分の言葉で伝える楽しさを軸に、両方をつなぐ設計が要ると思います。', false, now() - interval '4773 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--moral-education', 'room-subject-teaching--community--moral-education-t2', 'しんじ', '道徳研究会', '『正解』を当てにいく道徳では意味がないと思います。', false, now() - interval '4810 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--moral-education', 'room-subject-teaching--community--moral-education-t2', 'うめ子', '高校国語', '評価が入ったことで、子どもが教員の望む答えを書く傾向が強まった。本来は答えのない問いに向き合い、揺れながら考える時間のはず。点数化しにくくても、考えるプロセスそのものを大事にする設計に戻したいです。', false, now() - interval '4847 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--pe-health', 'room-subject-teaching--community--pe-health-t2', 'まっちょ', '体育会系', '順位だけ強調すると、運動嫩いを生むだけになりがちです。', false, now() - interval '4884 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--pe-health', 'room-subject-teaching--community--pe-health-t2', 'ぽてと', '学童支援員', '競争は意欲を引き出す面もあるが、勝ち負けが固定化すると苦手な子は早々に諸める。順位より『自分の記録がどう伸びたか』を見える化するなど、一人ひとりの達成を軸にする工夫が要ると思います。', false, now() - interval '4921 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--pe-health', 'room-subject-teaching--community--pe-health-t2', 'まろん', '養護教諭', '『できた』体験のほうが長く残ります。', false, now() - interval '4958 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--music-art', 'room-subject-teaching--community--music-art-t2', 'ドレミ', '音楽', '基礎技能がないと自由な表現も広がらない一方、技術練習ばかりでは『やらされ』になり、表現する喜びが薄れる。まず楽しいと感じる入り口を作り、必要な技能はその中で身につける順序が大事だと思います。', false, now() - interval '4995 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--home-economics-technology', 'room-subject-teaching--community--home-economics-technology-t2', 'おむすび', '家庭科', '調理や金銭管理など、生きる力は学校でも扱う価値があります。', false, now() - interval '5032 minutes'),
