  (gen_random_uuid(), 'room-subject-teaching--community--integrated-inquiry-time', 'room-subject-teaching--community--integrated-inquiry-time-t2', 'ごましお', '主幹教諭', '教科の壁を越えた学びは理想だが、時間割や教員配置の制約で『やりにくい』のが現実。総合の時間を軸に、各教科の知識を持ち寄るテーマを設定すると、現場でも回せる横断設計になると思います。', false, now() - interval '5106 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--information-subject', 'room-subject-teaching--community--information-subject-t2', 'テック岡', '情報科', '技術だけ教えても、使い方の倫理が伴わなければ危うい。両輪です。', false, now() - interval '5143 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--information-subject', 'room-subject-teaching--community--information-subject-t2', '父さん', '元エンジニア', 'プログラミングなどの技術力は将来の選択肢を広げるが、個人情報や著作権、誹謗中傷への意識が抜けると、技術が凶器になりかねない。モラルと技術は切り離さず、実例を通して同時に学ばせたいです。', false, now() - interval '5180 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--career-guidance', 'room-subject-teaching--community--career-guidance-t2', 'はるか', '探究コーディネーター', '偏差値は分かりやすい指標だが、それだけで進路を決めると『入れる学校』に流される。本人が何に夢中になれるかを軸に、多様な進路情報を示すことが、変化の時代の進路指導だと思います。', false, now() - interval '5217 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--career-guidance', 'room-subject-teaching--community--career-guidance-t2', 'ゆずぽん', '3児の母', '数値以外の物差しを親子で持ちたい。', false, now() - interval '5254 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--career-guidance', 'room-subject-teaching--community--career-guidance-t2', 'うめ子', '高校国語', '脱却したくても、入試制度が偏差値前提だと現場も動きにくい。', false, now() - interval '5291 minutes'),
  (gen_random_uuid(), 'room-subject-teaching--community--career-guidance', 'room-subject-teaching--community--career-guidance-t2', 'とんかつ', '保護者会長', '本人の『好き』を一番に考えたい。', false, now() - interval '5328 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--digital-textbook', 'room-ai-technology--community--digital-textbook-t3', 'うめ子', '高校国語', '二者択一でなく、目的で使い分けるのが現実的です。', false, now() - interval '5365 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--digital-textbook', 'room-ai-technology--community--digital-textbook-t3', 'ふじやま', '校務DX担当', '集中して読む場面は紙、検索や動画連動・共同編集はデジタル、と場面で選ぶのが自然。ただ使い分けの基準を現場の裁量に丸投げすると中途半端になりがちなので、学校として一定の方針を示してほしいです。', false, now() - interval '5402 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--digital-textbook', 'room-ai-technology--community--digital-textbook-t3', 'ゆずぽん', '3児の母', '家でも学校でもデジタルだと、紙の本をめくる経験そのものが減ります。', false, now() - interval '5439 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--edtech-adoption', 'room-ai-technology--community--edtech-adoption-t3', 'テック岡', '情報科', '無料サービスは『データが商品』のことが多い。何と引き換えかを見て使いたい。', false, now() - interval '5476 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--edtech-adoption', 'room-ai-technology--community--edtech-adoption-t3', 'ふじやま', '校務DX担当', '現場が無料だからと個別に導入すると、学校全体でデータ管理がバラバラになる。利用規約のチェック体制を整え、どのサービスを使うか組織で判断する仕組みが要る。安さの裏のリスクを見ぬく目が大事です。', false, now() - interval '5513 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--ai-literacy-moral', 'room-ai-technology--community--ai-literacy-moral-t3', '森のくま', 'スクールカウンセラー', '情報モラルは学校か家庭かではなく、両者が同じ言葉で語ることが大事。学校が見取り図を示し、家庭が日常で実践する分担が現実的。トラブルは家庭で起きて学校に持ち込まれることが多く、連携しないと実効性がありません。', false, now() - interval '5550 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--ai-literacy-moral', 'room-ai-technology--community--ai-literacy-moral-t3', 'ごましお', '主幹教諭', '家庭に丸投げしても、詳しくない保護者は多い。', false, now() - interval '5587 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--ai-literacy-moral', 'room-ai-technology--community--ai-literacy-moral-t3', 'ゆずぽん', '3児の母', '子どものほうが親よりデバイスに詳しい現状では、学校の専門的な支援が要ります。', false, now() - interval '5624 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--personalized-learning', 'room-ai-technology--community--personalized-learning-t3', 'コタロー', '大学院生', '『点数が上がる』だけの最適化に陥らないか。誰のための最適化かが問われます。', false, now() - interval '5661 minutes'),
  (gen_random_uuid(), 'room-ai-technology--community--personalized-learning', 'room-ai-technology--community--personalized-learning-t3', 'テック岡', '情報科', '最適化のアルゴリズムがブラックボックスのままだと、なぜその問題が出たのか説明できない。透明性の確保が必須で、何より子ども本人が『どう学びたいか』を言える状態でないと、誰かの都合の最適化になってしまいます。', false, now() - interval '5698 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--inquiry-pbl', 'room-evaluation-curriculum--community--inquiry-pbl-t3', 'はるか', '探究コーディネーター', '両者は対立しません。むしろ補い合う関係です。', false, now() - interval '5735 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--inquiry-pbl', 'room-evaluation-curriculum--community--inquiry-pbl-t3', 'カエル先生', '中学数学', '教科で身につけた知識を探究で使い、探究で生まれた問いを教科で深める循環が理想。ただ限られた授業時数で両方を成立させるのは至難で、基礎をデジタルで効率化し、浮いた時間を探究に回す工夫が要ります。', false, now() - interval '5772 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--inquiry-pbl', 'room-evaluation-curriculum--community--inquiry-pbl-t3', 'とんかつ', '保護者会長', '受験を控えると、探究に時間を割いて大丈夫か不安になります。', false, now() - interval '5809 minutes'),
