  (gen_random_uuid(), 'room-evaluation-curriculum--community--homework', 'room-evaluation-curriculum--community--homework-t3', 'ぱんだ', '小学校教員', '学校内で完結する学習時間を確保したい。', false, now() - interval '5883 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--homework', 'room-evaluation-curriculum--community--homework-t3', 'くるみ', '放デイ職員', '放課後の学習支援を充実させれば、格差はかなり緩和できます。', false, now() - interval '5920 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--homework', 'room-evaluation-curriculum--community--homework-t3', 'あられ', '小1ママ', '共働きだと見る時間がないのが現実です。', false, now() - interval '5957 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--course-of-study-revision', 'room-evaluation-curriculum--community--course-of-study-revision-t3', 'タケじい', '元校長', '『増やす』議論より『何を処理できるか』を先に決めるべきです。', false, now() - interval '5994 minutes'),
