  (gen_random_uuid(), 'room-evaluation-curriculum--community--non-cognitive-skills', 'room-evaluation-curriculum--community--non-cognitive-skills-t3', 'コタロー', '大学院生', '優劣ではなく車の両輪。優先順位の発想自体が学びを狭めます。', false, now() - interval '6068 minutes'),
  (gen_random_uuid(), 'room-evaluation-curriculum--community--non-cognitive-skills', 'room-evaluation-curriculum--community--non-cognitive-skills-t3', 'ごましお', '主幹教諭', '現場で限られた時間を配分する以上、どちらに重きを置くかの選択は避けられない。結局テストで測れる認知が優先されがちだが、社会に出てから効いてくるのは非認知の力。長い目で見る視点を忘れたくないです。', false, now() - interval '6105 minutes'),
